 * 
 * @return List of course statistics
 */
std::vector<CourseStats> query_course_enrollment_stats() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // 1. Connect to SQLite database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto conn = *conn_result;

  // 2. Create Course and Enrollment tables
  auto create_course_result = conn.execute(
      sqlgen::transpilation::to_sql(create_table<Course>)
  );
  if (!create_course_result) {
    throw std::runtime_error("Failed to create Course table");
  }

  auto create_enrollment_result = conn.execute(
      sqlgen::transpilation::to_sql(create_table<Enrollment>)
  );
  if (!create_enrollment_result) {
    throw std::runtime_error("Failed to create Enrollment table");
  }

  // 3. Query database with LEFT JOIN, GROUP BY, COUNT, and AVG
  auto query = select_from<Course, "c">(
      "c.title"_c,
      count("e.enrollment_id"_e).as("student_count"),
      avg("e.grade"_e).as("avg_grade")
  ) | left_join<Enrollment, "e">("c.course_id"_c == "e.course_id"_e)
    | group_by("c.course_id"_c, "c.title"_c)
    | to<std::vector<CourseStats>>;

  // 4. Execute query and return results
  auto result = query(conn);
  if (!result) {
    throw std::runtime_error("Query execution failed");
  }

  return *result;
}

}  // namespace query_course_enrollment_stats
