std::vector<DailyTraffic> query_daily_traffic_metrics() {
  using namespace sqlgen::literals;

  // 1. Connect to the SQLite database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return {}; // Return empty vector on connection failure
  }
  auto conn = conn_result.value();

  // 2. Build the query using sqlgen::select_from
  auto query = sqlgen::select_from<PageVisit>(
      // 3. Extract date from visit_time using strftime and alias it
      sqlgen::strftime("%Y-%m-%d", &PageVisit::visit_time).as<"visit_date">(),
      // 4. Use count() aggregation for total visits
      sqlgen::count().as<"total_visits">(),
      // 5. Use count_distinct() aggregation for unique URLs
      sqlgen::count_distinct(&PageVisit::url).as<"unique_pages">()
  )
  // 6. Apply group_by with the aliased date column
  | sqlgen::group_by("visit_date"_c)
  // 7. Apply order_by with the aliased date column
  | sqlgen::order_by("visit_date"_c);

  // 8. Execute the query and map results to DailyTraffic struct
  auto results = query(conn);
  if (!results) {
    return {}; // Return empty vector on query execution failure
