  std::vector<DailyTraffic> daily_traffic;
  for (const auto& [visit_date, total_visits, unique_pages] : results.value()) {
    daily_traffic.push_back(DailyTraffic{
        .visit_date = visit_date,
        .total_visits = total_visits,
        .unique_pages = unique_pages
    });
  }

  return daily_traffic;
}

}  // namespace query_daily_traffic_metrics
