  // Connect to the SQLite database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false;
  }
  auto conn = *conn_result;

  // Check if User table exists by attempting to read from it
  auto read_result = conn->read<std::vector<User>>();
  if (!read_result) {
    // Table doesn't exist, cannot perform migration
    return false;
  }

  try {
