namespace analyze_social_network {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
  std::string email;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> join_date;
  std::string city;
};

struct Friendship {
  int user1_id;
  int user2_id;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> created_at;
};

struct FriendConnection {
  std::string user1_name;
  std::string user2_name;
};

std::vector<FriendConnection> analyze_social_network_impl(const std::vector<User>& users, const std::vector<Friendship>& friendships) {
  using namespace sqlgen::literals;

  // Connect to SQLite database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Create tables if they don't exist
  conn | sqlgen::create_table<User> | sqlgen::if_not_exists;
  conn | sqlgen::create_table<Friendship> | sqlgen::if_not_exists;

  // Insert user data
  conn | sqlgen::write(users);

  // Insert friendship data
  conn | sqlgen::write(friendships);

  // Query 1: Find mutual friends using self-join
  auto mutual_friends_query = 
      sqlgen::select_from<User, "u1">("username"_t1, "username"_t2)
      | sqlgen::inner_join<Friendship, "f1">("user_id"_t1 == "user_id1"_t1)
      | sqlgen::inner_join<User, "u2">("user_id2"_t1 == "user_id"_t2)
      | sqlgen::inner_join<Friendship, "f2">("user_id"_t2 == "user_id1"_t2)
      | sqlgen::where("user_id"_t1 < "user_id"_t2)
      | sqlgen::group_by("user_id"_t1, "user_id"_t2)
      | sqlgen::having(sqlgen::count() > 0);

  // Execute mutual friends query and map results
  auto mutual_results = mutual_friends_query(conn);
  std::vector<FriendConnection> mutual_connections;
  for (const auto& row : mutual_results) {
    mutual_connections.push_back(FriendConnection{
        .user1_name = std::get<0>(row),
        .user2_name = std::get<1>(row)
    });
  }

  // Query 2: Users with more than average friends
  auto avg_friend_count = 
      sqlgen::select_from<User, "u">("user_id"_t1, sqlgen::count().as<"friend_count">)
      | sqlgen::left_join<Friendship, "f">("user_id"_t1 == "user_id1"_t1)
      | sqlgen::group_by("user_id"_t1)
      | sqlgen::select_from(sqlgen::avg("friend_count"_t1).as<"avg_count">);

  // Query 3: Friend-of-friend relationships
  auto friend_of_friend_query = 
      sqlgen::select_from<User, "u1">("username"_t1, "username"_t2)
      | sqlgen::inner_join<Friendship, "f1">("user_id"_t1 == "user_id1"_t1)
      | sqlgen::inner_join<User, "u2">("user_id2"_t1 == "user_id"_t2)
      | sqlgen::inner_join<Friendship, "f2">("user_id"_t2 == "user_id1"_t2)
      | sqlgen::where("user_id"_t1 != "user_id"_t2)
      | sqlgen::group_by("user_id"_t1, "user_id"_t2)
      | sqlgen::having(sqlgen::count() == 1);

  // Query 4: Count friends per user
  auto friends_per_user_query = 
      sqlgen::select_from<User, "u">("user_id"_t1, sqlgen::count().as<"friend_count">)
      | sqlgen::left_join<Friendship, "f">("user_id"_t1 == "user_id1"_t1)
      | sqlgen::group_by("user_id"_t1)
      | sqlgen::order_by("friend_count"_t1.desc());

  // Query 5: Recommend users in same city not yet friends
  auto recommendation_query = 
      sqlgen::select_from<User, "u1">("username"_t1, "username"_t2)
      | sqlgen::inner_join<User, "u2">("city"_t1 == "city"_t2)
      | sqlgen::where("user_id"_t1 < "user_id"_t2)
      | sqlgen::not_exists(
          sqlgen::select_from<Friendship, "f">()
          | sqlgen::where(("user_id1"_t1 == "user_id"_t1 && "user_id2"_t1 == "user_id"_t2) 
                         || ("user_id1"_t1 == "user_id"_t2 && "user_id2"_t1 == "user_id"_t1))
      );

  // Return mutual friend connections as specified in the return type
  return mutual_connections;
}

}  // namespace analyze_social_network
```

**Key Implementation Details:**

1. **Database Connection**: Uses `sqlgen::sqlite::connect()` to establish connection to "test_db.sqlite"
2. **Table Creation**: Creates User and Friendship tables using `sqlgen::create_table` with `sqlgen::if_not_exists`
3. **Data Insertion**: Uses `sqlgen::write()` to insert user and friendship data
4. **Self-Join Queries**: Implements mutual friends detection using nested self-joins
5. **Aggregation Functions**: Uses `sqlgen::count()` and `sqlgen::avg()` for statistical analysis
6. **WHERE Conditions**: Implements complex filtering using column comparisons
7. **Result Mapping**: Converts query results to `FriendConnection` objects

