#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace group_by_with_aggregations {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string name;
};

struct Post {
  sqlgen::PrimaryKey<int> post_id;
  int user_id;
  std::string content;
};

struct Stats {
  sqlgen::PrimaryKey<int> user_id;
  std::string name;
  int post_count;
  std::optional<double> avg_length;
};

/**
 * Description: This function retrieves user statistics including post count and average post length.
 * Returns: std::vector<Stats>.
 */
std::vector<Stats> group_by_with_aggregations() {
  using namespace sqlgen::literals;

  // Connect to the database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Build the query using sqlgen's fluent interface
  auto query = sqlgen::read<std::vector<Stats>>
               | sqlgen::inner_join<User, "user">("user_id"_c == "user_id"_c)
               | sqlgen::group_by("user_id"_c, "name"_c)
               | sqlgen::select(
                   "user_id"_c,
                   "name"_c,
                   sqlgen::count().as<"post_count">(),
                   sqlgen::avg(sqlgen::length("content"_c)).as<"avg_length">()
                 );

  // Execute the query and return results
  return query(conn).value();
}

}  // namespace group_by_with_aggregations
```

## Key Implementation Points:

1. **Database Connection**: Uses `sqlgen::sqlite::connect("test_db.sqlite")` to establish connection
2. **Table Join**: Uses `inner_join` to join `Post` and `User` tables on `user_id`
3. **Grouping**: Groups by both `user_id` and `name` columns using `group_by`
4. **Aggregations**: 
   - `sqlgen::count()` for post count
   - `sqlgen::avg(sqlgen::length("content"_c))` for average content length
5. **Column Aliasing**: Uses `.as<"alias_name">()` to match the `Stats` struct field names
6. **Query Execution**: Calls the query object with the connection and extracts results

The implementation follows sqlgen's fluent API pattern and correctly maps the SQL GROUP BY query structure to the C++ type system using the provided aggregations and column operations.

